const xml = $input.first().json.data;
const text = (value = '') => value.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').replace(/<[^>]*>/g, '').trim();
const pick = (block, tag) => text((block.match(new RegExp(`<${tag}[^>]*>([\s\S]*?)<\/${tag}>`, 'i')) || [])[1] || '');
return [...xml.matchAll(/<item>([\s\S]*?)<\/item>/gi)].slice(0, 10).map((match) => {
  const item = match[1]; const title = pick(item, 'title'); const published = pick(item, 'pubDate'); const traffic = pick(item, 'ht:approx_traffic');
  const sourceUrl = `https://trends.google.com/trends/explore?geo=IN&q=${encodeURIComponent(title)}`;
  return { json: { title: `Google Trends: ${title}`, sourceUrl, publishedAt: published, sourceName: 'Google Trends RSS', content: `Trending search: ${title}. Approximate traffic: ${traffic || 'not provided'}. Source: Google Trends Trending Now.` } };
});
